build for javascript backend

when user sends calculation to /api/calculate:
  # Check for division by zero
  is_divide = calculation's operation is 'divide'
  is_zero_divisor = calculation's b is 0
  if is_divide and is_zero_divisor:
    send back 'Division by zero' with status 400

  result is 0
  if calculation's operation is 'add':
    result is calculation's a + calculation's b
  if calculation's operation is 'subtract':
    result is calculation's a - calculation's b
  if calculation's operation is 'multiply':
    result is calculation's a * calculation's b
  if calculation's operation is 'divide':
    result is calculation's a / calculation's b

  send back { result: result }
